mapper.select:
select l.*, u.real_name as operator_name from sys_operation_log l left join sys_user u on u.id = l.user_id where 1 = 1
and l.module_name = #{moduleName}
and (l.action_name like concat('%', #{keyword}, '%') or l.request_uri like concat('%', #{keyword}, '%'))
order by l.create_time desc, l.id desc limit #{offset}, #{pageSize}

select count(1) from sys_operation_log l where 1 = 1
and l.module_name = #{moduleName}
and (l.action_name like concat('%', #{keyword}, '%') or l.request_uri like concat('%', #{keyword}, '%'))

mapper.insert:

insert into sys_operation_log(
  user_id, module_name, action_name, request_method, request_uri, request_ip, result_code, result_msg, biz_id, create_time
) values (
  #{userId}, #{moduleName}, #{actionName}, #{requestMethod}, #{requestUri}, #{requestIp}, #{resultCode}, #{resultMsg}, #{bizId}, #{createTime}
)
